import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { Toaster } from 'react-hot-toast';
import { AuthProvider, useAuth } from './store/AuthContext';
import './styles/global.css';

// Pages
import LandingPage from './pages/LandingPage';
import LoginPage from './pages/LoginPage';
import RegisterPage from './pages/RegisterPage';
import DashboardPage from './pages/DashboardPage';
import GeneratePage from './pages/GeneratePage';
import EditorPage from './pages/EditorPage';
import DocumentsPage from './pages/DocumentsPage';

// Layout
import Navbar from './components/layout/Navbar';

// ─── Protected Route ──────────────────────────────────────────────────────────
const ProtectedRoute = ({ children }) => {
  const { user, loading } = useAuth();
  if (loading) return <LoadingScreen />;
  if (!user) return <Navigate to="/login" replace />;
  return children;
};

// ─── Public Route (redirect if logged in) ────────────────────────────────────
const PublicRoute = ({ children }) => {
  const { user, loading } = useAuth();
  if (loading) return <LoadingScreen />;
  if (user) return <Navigate to="/dashboard" replace />;
  return children;
};

const LoadingScreen = () => (
  <div style={{
    minHeight: '100vh',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    background: 'var(--bg-primary)',
    flexDirection: 'column',
    gap: '16px',
  }}>
    <div style={{
      width: '48px', height: '48px',
      border: '3px solid var(--border)',
      borderTopColor: 'var(--accent)',
      borderRadius: '50%',
      animation: 'spin 0.8s linear infinite',
    }} />
    <p style={{ color: 'var(--text-muted)', fontSize: '14px' }}>Loading...</p>
  </div>
);

// ─── App Shell ────────────────────────────────────────────────────────────────
const AppShell = () => {
  const { user } = useAuth();

  return (
    <>
      {/* Ambient Orbs */}
      <div className="orb orb-1" />
      <div className="orb orb-2" />

      {user && <Navbar />}

      <div style={{ position: 'relative', zIndex: 1 }}>
        <Routes>
          {/* Public */}
          <Route path="/" element={
            <PublicRoute><LandingPage /></PublicRoute>
          } />
          <Route path="/login" element={
            <PublicRoute><LoginPage /></PublicRoute>
          } />
          <Route path="/register" element={
            <PublicRoute><RegisterPage /></PublicRoute>
          } />

          {/* Protected */}
          <Route path="/dashboard" element={
            <ProtectedRoute><DashboardPage /></ProtectedRoute>
          } />
          <Route path="/generate" element={
            <ProtectedRoute><GeneratePage /></ProtectedRoute>
          } />
          <Route path="/generate/:type" element={
            <ProtectedRoute><GeneratePage /></ProtectedRoute>
          } />
          <Route path="/editor/:id" element={
            <ProtectedRoute><EditorPage /></ProtectedRoute>
          } />
          <Route path="/documents" element={
            <ProtectedRoute><DocumentsPage /></ProtectedRoute>
          } />

          {/* Fallback */}
          <Route path="*" element={<Navigate to="/" replace />} />
        </Routes>
      </div>

      <Toaster
        position="top-right"
        toastOptions={{
          style: {
            background: 'var(--bg-card)',
            color: 'var(--text-primary)',
            border: '1px solid var(--border)',
            borderRadius: 'var(--radius)',
            fontFamily: 'var(--font)',
            fontSize: '14px',
          },
          success: {
            iconTheme: { primary: 'var(--accent-green)', secondary: 'var(--bg-card)' },
          },
          error: {
            iconTheme: { primary: 'var(--accent-secondary)', secondary: 'var(--bg-card)' },
          },
        }}
      />
    </>
  );
};

function App() {
  return (
    <Router>
      <AuthProvider>
        <AppShell />
      </AuthProvider>
    </Router>
  );
}

export default App;
